import { useSelector } from "react-redux";
import { useDispatch } from "react-redux";

import { toggleCartActions } from "../../store";

import classes from "./CartButton.module.css";

const CartButton = (props) => {
  const dispatch = useDispatch();

  const addToCartState = useSelector((state) => state.addToCart.value);

  const toggleCartState = useSelector((state) => state.toggleCart);

  const handleToggleCart = () => {
    console.log(addToCartState);
    if (addToCartState > 0) {
      dispatch(toggleCartActions.toggleCart());
    }
  };

  return (
    <button className={classes.button} onClick={handleToggleCart}>
      <span>{!toggleCartState ? "My" : "Close"} Cart</span>
      <span className={classes.badge}>{addToCartState}</span>
    </button>
  );
};

export default CartButton;
